import { Component, OnInit } from '@angular/core';
import { ReservaService } from '../../services/reserva.service';

@Component({
  selector: 'app-historic',
  templateUrl: './historic.component.html'
})
export class HistoricComponent implements OnInit {
  reserves: any[] = [];
  loading = true;
  error = '';
  missatgeCancelar = '';

  constructor(private reservaService: ReservaService) {}

  ngOnInit(): void {
    this.carregarReserves();
  }

  carregarReserves(): void {
    this.loading = true;
    this.reservaService.getMevesReserves().subscribe({
      next: (r) => {
        this.reserves = r;
        this.loading = false;
      },
      error: () => {
        this.error = 'No s\'han pogut carregar les reserves.';
        this.loading = false;
      }
    });
  }

  cancellar(id: string): void {
    if (!confirm('Segur que vols cancel·lar aquesta reserva?')) return;
    this.reservaService.cancellarReserva(id).subscribe({
      next: () => {
        this.missatgeCancelar = 'Reserva cancel·lada.';
        this.carregarReserves();
      },
      error: (err) => {
        this.error = err.error?.message || 'No s\'ha pogut cancel·lar.';
      }
    });
  }

  esCancelable(estat: string): boolean {
    return estat === 'PENDING' || estat === 'CONFIRMED';
  }

  badgeClass(estat: string): string {
    const m: any = {
      PENDING: 'bg-warning text-dark',
      CONFIRMED: 'bg-primary',
      COMPLETED: 'bg-success',
      CANCELLED: 'bg-danger'
    };
    return m[estat] || 'bg-secondary';
  }
}
<h4 class="mb-4"><i class="bi bi-clock-history me-2"></i>Historial de reserves</h4>

<div class="alert alert-success" *ngIf="missatgeCancelar">{{ missatgeCancelar }}</div>
<div class="alert alert-danger" *ngIf="error">{{ error }}</div>

<div class="text-center py-5" *ngIf="loading">
  <div class="spinner-border"></div>
</div>

<div *ngIf="!loading">
  <div *ngIf="reserves.length === 0" class="text-center text-muted py-5">
    <i class="bi bi-calendar-x fs-1"></i>
    <p class="mt-2">No tens cap reserva encara.</p>
    <a routerLink="/reserves" class="btn btn-dark">Crear primera reserva</a>
  </div>

  <div class="table-responsive" *ngIf="reserves.length > 0">
    <table class="table table-hover align-middle">
      <thead class="table-dark">
        <tr>
          <th>Pista</th>
          <th>Inici</th>
          <th>Fi</th>
          <th>Arma</th>
          <th>Estat</th>
          <th>Acció</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let r of reserves">
          <td>{{ r.pistaId }}</td>
          <td>{{ r.dataHoraInici | date:'dd/MM/yyyy HH:mm' }}</td>
          <td>{{ r.dataHoraFi | date:'dd/MM/yyyy HH:mm' }}</td>
          <td>{{ r.tipusArma || '–' }}</td>
          <td>
            <span class="badge" [ngClass]="badgeClass(r.estat)">{{ r.estat }}</span>
          </td>
          <td>
            <button class="btn btn-sm btn-outline-danger"
              *ngIf="esCancelable(r.estat)"
              (click)="cancellar(r.id)">
              <i class="bi bi-x-circle"></i> Cancel·lar
            </button>
            <span class="text-muted small" *ngIf="!esCancelable(r.estat)">–</span>
          </td>
        </tr>
      </tbody>
    </table>
  </div>
</div>
